import React from "react";

function Navbar() {
  return (
    <nav className="navbar">
      <div className="navbar-inner">
        <h2>🏋️ FitCare AI Dashboard</h2>
        <p>Your smart health and fitness companion</p>
      </div>
    </nav>
  );
}

export default Navbar;
